class Solution {
    public int findBestValue(int[] arr, int target) {
        Arrays.sort(arr);
        int sum = 0;
        for (int i = 0; i < arr.length; i++) {
            sum += arr[i];
            if (sum > target) {
                int diff = Math.abs(sum - target);
                int diff2 = Math.abs(target - sum + arr[i]);
                return Math.min(arr[i], diff < diff2 ? arr[i - 1] : arr[i]);
            }
        }
        return arr[arr.length - 1];
    }
}
